try {
  const now = new Date();
  const in21Days = new Date(now.getTime() + 21 * 24 * 60 * 60 * 1000);

  const holidays = [
    {name: "New Year's Day", month: 1, day: 1},
    {name: "Valentine's Day", month: 2, day: 14},
    {name: "St. Patrick's Day", month: 3, day: 17},
    {name: "Easter Sunday", month: 4, day: 20},
    {name: "Mother's Day", month: 5, day: 11},
    {name: "Memorial Day", month: 5, day: 26},
    {name: "Father's Day", month: 6, day: 15},
    {name: "Independence Day", month: 7, day: 4},
    {name: "Labor Day", month: 9, day: 1},
    {name: "Halloween", month: 10, day: 31},
    {name: "Thanksgiving", month: 11, day: 27},
    {name: "Black Friday", month: 11, day: 28},
    {name: "Cyber Monday", month: 12, day: 1},
    {name: "Christmas", month: 12, day: 25},
    {name: "New Year's Eve", month: 12, day: 31}
  ];

  let upcomingHoliday = null;
  for (const holiday of holidays) {
    const holidayDate = new Date(now.getFullYear(), holiday.month - 1, holiday.day);
    if (holidayDate >= now && holidayDate <= in21Days) {
      upcomingHoliday = holiday;
      break;
    }
  }

  return [{
    json: {
      has_holiday: upcomingHoliday !== null,
      holiday_name: upcomingHoliday ? upcomingHoliday.name : null,
      holiday_date: upcomingHoliday ? new Date(now.getFullYear(), upcomingHoliday.month - 1, upcomingHoliday.day).toISOString().split('T')[0] : null,
      days_until: upcomingHoliday ? Math.floor((new Date(now.getFullYear(), upcomingHoliday.month - 1, upcomingHoliday.day) - now) / (1000 * 60 * 60 * 24)) : null
    }
  }];
} catch(e) {
  return [{json: {error: e.message, has_holiday: false}}];
}

