try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    const holiday = $node['Check Upcoming Holidays'].json;
    let content;
    try {
      const text = item.json.content[0].text;
      content = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      content = match ? JSON.parse(match[0]) : {
        instagram_caption: '',
        instagram_caption_2: '',
        facebook_post: '',
        email_subject: '',
        email_body: '',
        google_ad_headline: '',
        google_ad_description: '',
        content_theme: holiday.holiday_name,
        campaign_name: holiday.holiday_name + ' Campaign'
      };
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      holiday_name: holiday.holiday_name,
      instagram_caption: content.instagram_caption || '',
      instagram_caption_2: content.instagram_caption_2 || '',
      facebook_post: content.facebook_post || '',
      email_subject: content.email_subject || '',
      email_body: content.email_body || '',
      google_ad_headline: content.google_ad_headline || '',
      google_ad_description: content.google_ad_description || '',
      content_theme: content.content_theme || holiday.holiday_name,
      campaign_name: content.campaign_name || holiday.holiday_name + ' Campaign',
      status: 'pending_approval',
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json: {error: e.message}}];
}
